/**
 * AMD module: confirm dialog for reset buttons in the teacher report.
 *
 * @module     mod_eledialeitnerflow/confirm_reset
 * @package    mod_eledialeitnerflow
 * @copyright  2024 eLeDia GmbH
 * @license    http://www.gnu.org/copyleft/gpl.html GNU GPL v3 or later
 */
define(["core/notification"],function(t){"use strict";return{init:function(){document.querySelectorAll("[data-confirm]").forEach(function(n){n.addEventListener("click",function(e){e.preventDefault();var i=n.getAttribute("data-confirm"),o=n.getAttribute("href");t.confirm(n.textContent.trim(),i,n.textContent.trim(),null,function(){window.location.href=o})})})}}});